import subprocess

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    try:
        command = input("Enter command to execute: ").strip()

        # Check if command is empty
        if not command:
            return "No command provided"

        # List of forbidden commands
        forbidden = ['rm', 'rmdir', 'del', 'format']

        # Check for forbidden commands
        if any(cmd in command.lower() for cmd in forbidden):
            return "Command not allowed for security reasons"

        # Execute command and capture output
        result = subprocess.run(command, shell=True, capture_output=True, text=True)

        if result.returncode == 0:
            return result.stdout
        else:
            return f"Error: {result.stderr}"

    except subprocess.SubprocessError as e:
        return f"Error executing command: {str(e)}"
    except Exception as e:
        return f"Unexpected error: {str(e)}"

import os
from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route("/command", methods=['POST'])
def executeCommand():
    try:
        data = request.get_json()
        if not data or 'command' not in data:
            return jsonify({'error': 'No command provided'}), 400

        command = data['command']
        # Basic validation - prevent dangerous commands
        dangerous_commands = [';', '&&', '||', '|', '>', '<', 'rm', 'sudo']
        if any(cmd in command.lower() for cmd in dangerous_commands):
            return jsonify({'error': 'Invalid command'}), 400

        # Execute command and get output
        output = os.popen(command).read()
        return jsonify({'output': output}), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500

