import logging

def isAuthorizedUser(userId):
    try:
        # Simplified authorization check
        return userId is not None and len(str(userId)) > 0
    except Exception as e:
        logging.error(f"Error checking user authorization: {str(e)}")
        return False

def getUserBankAccount(userId, connection):
    try:
        if not isAuthorizedUser(userId):
            raise PermissionError("User is not authorized")

        query = "SELECT * FROM bank_accounts WHERE user_id = %s"
        cursor = connection.cursor()
        cursor.execute(query, (userId,))
        result = cursor.fetchone()

        if result is None:
            raise ValueError(f"No bank account found for user {userId}")

        return result

    except PermissionError as pe:
        logging.error(f"Authorization error for user {userId}: {str(pe)}")
        raise
    except Exception as e:
        logging.error(f"Error retrieving bank account for user {userId}: {str(e)}")
        raise
    finally:
        if 'cursor' in locals():
            cursor.close()

