def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    if len(password) < 8:
        return False

    has_uppercase = False
    has_lowercase = False
    has_digit = False
    has_special = False
    special_chars = "!@#$%^&*()_+-=[]{}|;:,.<>?"

    for char in password:
        if char.isupper():
            has_uppercase = True
        elif char.islower():
            has_lowercase = True
        elif char.isdigit():
            has_digit = True
        elif char in special_chars:
            has_special = True

    return has_uppercase and has_lowercase and has_digit and has_special

import os


def invalidUsername(username):
    if not username or ' ' in username or len(username) > 32:
        return True
    invalid_chars = ['/', '\\', ':', '*', '?', '"', '<', '>', '|']
    return any(char in username for char in invalid_chars)


def raisePrivileges():
    os.seteuid(0)


def lowerPrivileges():
    os.seteuid(os.getuid())


def makeNewUserDir(username):
    if invalidUsername(username):
        return False

    try:
        raisePrivileges()
        user_dir = f"/home/{username}"
        os.makedirs(user_dir, exist_ok=True)
        os.chown(user_dir, 1000, 1000)
        os.chmod(user_dir, 0o700)
        return True
    except Exception:
        return False
    finally:
        lowerPrivileges()

import os, signal


def killProcess(processID):
    '''
    Kill the process with the given processID.
    '''
    try:
        os.kill(processID, signal.SIGTERM)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        return False

