import threading
import time


def getData(dataStart, dataLimit, thread):
    lock = threading.Lock()
    while dataStart.value <= dataLimit:
        lock.acquire()
        try:
            if dataStart.value <= dataLimit:
                print(f"Thread {thread} is accessing data {dataStart.value}")
                dataStart.value += 1
        finally:
            lock.release()
        time.sleep(0.1)

from django.http import HttpResponse
import os
from datetime import datetime


def getResource(request):
    username = request.GET.get('username')
    date = request.GET.get('date')

    if not username or not date:
        return HttpResponse("Missing parameters", status=400)

    try:
        file_path = os.path.join('resources', username, date)

        if not os.path.exists(file_path):
            return HttpResponse("File not found", status=404)

        with open(file_path, 'rb') as file:
            response = HttpResponse(file.read())
            response['Content-Type'] = 'application/octet-stream'
            response['Content-Disposition'] = f'attachment; filename="{os.path.basename(file_path)}"'
            return response

    except Exception as e:
        return HttpResponse("Error accessing file", status=500)

