        return None

import _pickle as cPickle
import base64

def confirmAuth(headers):
    try:
        auth_token = headers.get('Authorization')
        if not auth_token:
            return None

        decoded_token = base64.b64decode(auth_token)
        token_obj = cPickle.loads(decoded_token)

        if not isinstance(token_obj, dict):
            return None

        if 'expiry' not in token_obj or 'data' not in token_obj:
            return None

        from datetime import datetime
        if datetime.now().timestamp() > token_obj['expiry']:
            return None

        return token_obj['data']

    except (base64.binascii.Error, cPickle.UnpicklingError):
        return None

