def dispatchCommand(command, user, args):
    if not user.authenticated and command != 'login':
        raise PermissionError("User must be authenticated first")

    if command == 'login':
        return loginUser(user, args)
    elif command == 'retrieve_file':
        if not user.authenticated:
            raise PermissionError("Authentication required to retrieve files")
        return sendFile(user, args)
    elif command == 'list_files':
        if not user.authenticated:
            raise PermissionError("Authentication required to list files")
        return listFiles(user)
    else:
        raise ValueError(f"Unknown command: {command}")

def loginUser(user, args):
    if len(args) != 2:
        raise ValueError("Login requires username and password")
    username, password = args
    user.authenticate(username, password)
    return "Login successful"

def sendFile(user, args):
    if len(args) != 1:
        raise ValueError("File retrieval requires filename")
    filename = args[0]
    if not user.hasAccessTo(filename):
        raise PermissionError(f"No permission to access file: {filename}")
    return user.retrieveFile(filename)

def listFiles(user):
    return user.getAccessibleFiles()

