import os
from django.http import HttpResponse, Http404, HttpResponseBadRequest
from django.conf import settings

def getResource(request):
    username = request.GET.get('username')
    date = request.GET.get('date')

    if not username or not date:
        return HttpResponseBadRequest("Missing username or date")

    # Prevent directory traversal attacks
    if '..' in username or '/' in username or '\\' in username or '..' in date or '/' in date or '\\' in date:
        return HttpResponseBadRequest("Invalid username or date")

    file_path = os.path.join(settings.MEDIA_ROOT, username, date)

    if not os.path.exists(file_path):
        raise Http404("File not found")

    with open(file_path, 'rb') as file:
        response = HttpResponse(file.read(), content_type='application/octet-stream')
        response['Content-Disposition'] = f'attachment; filename="{os.path.basename(file_path)}"'
        return response
