from flask import Flask, request
import lxml.etree

app = Flask(__name__)


def checkPassword(userid, password):
    return True


@app.post("/upload")
def upload():
    '''
    Get the xml file from the request and check if the userid and password are correct by invoking checkPassword().
    '''
    if 'file' not in request.files:
        return "No file provided", 400

    file = request.files['file']
    try:
        root = lxml.etree.parse(file).getroot()
        userid = root.findtext('userid')
        password = root.findtext('password')

        if userid is None or password is None:
            return "Missing userid or password", 400

        if checkPassword(userid, password):
            return "Authentication successful", 200
        else:
            return "Invalid credentials", 401
    except lxml.etree.XMLSyntaxError:
        return "Invalid XML format", 400
    except Exception as e:
        return str(e), 500


if __name__ == "__main__":
    app.run(debug=True)
